import{_ as o,c as s,o as r,a as e,b as a}from"./app.426dd711.js";const j=JSON.parse('{"title":"10. Semanas de 40 Horas (40 Hour Week)","description":"","frontmatter":{},"headers":[],"relativePath":"practices/40-hour-week.md"}'),n={name:"practices/40-hour-week.md"},t=e("h1",{id:"_10-semanas-de-40-horas-40-hour-week",tabindex:"-1"},[a("10. Semanas de 40 Horas "),e("em",null,"(40 Hour Week)"),a(),e("a",{class:"header-anchor",href:"#_10-semanas-de-40-horas-40-hour-week","aria-hidden":"true"},"#")],-1),d=e("p",null,"Esta pr\xE1ctica propone que los desarrolladores dediquen 40 horas de trabajo por semana, de tal forma se evita que los programadores se fatiguen y hace que las horas de trabajo sean altamente productivas. Igualmente asegura la calidad del equipo, considerando que \xE9ste, no debe asumir responsabilidades que le demanden mayor esfuerzo del que humanamente se puede disponer.",-1),l=e("p",null,"No hace falta dedicar largas jornadas de duro trabajo, pues esto no es garant\xEDa de acabar antes. Un equipo \u201Cdescansado\u201D, sin esfuerzos desmedidos, logra un mejor resultado. Es importante que los desarrolladores de software siempre tengan la mente fresca para construir el software. Posiblemente largas jornadas de trabajo provocaran errores debidos a la concentraci\xF3n y a la motivaci\xF3n del equipo. Es dif\xEDcil mantenerse en plenitud de facultades durante toda la jornada de trabajo si esta es larga.",-1),i=e("blockquote",null,[e("p",null,"Esto marca una diferencia radical con otras metodolog\xEDas, sobre todo, con aquellas que siguen una l\xEDnea tradicional donde las estimaciones \u201Cde tiempo\u201D deficientes obligan al Equipo de Desarrollo, a sobre-esfuerzos significativos. Los proyectos de desarrollo tradicionales suelen necesitar horas extras y esfuerzos heroicos para entregar el software en la fecha prometida. El resultado suele ser un equipo agotado y menos productivo, lo cual genera una fuerte baja en la calidad del software producido, ya sea en el corto, mediano o largo plazo. Horas extras y esfuerzos heroicos son se\xF1ales de problemas mayores, como por ejemplo compromisos por encima de las posibilidades, estimaciones pobres, falta de recursos, etc.")],-1),c=e("p",null,"Sin embargo, varias organizaciones aceptan convivir con este problema continuamente. Seguramente habr\xE1n excepciones donde, seg\xFAn el modelo del negocio que lo necesite, se tendr\xE1n que alargar eventualmente las jornadas. En tal caso y de todas maneras, 40 horas de trabajo a la semana pueden distribuirse de muchas formas.",-1),u=[t,d,l,i,c];function m(p,h,f,_,b,g){return r(),s("div",null,u)}const v=o(n,[["render",m]]);export{j as __pageData,v as default};
